(() => {
  const $ = (s, r = document) => r.querySelector(s);
  const $$ = (s, r = document) => Array.from(r.querySelectorAll(s));

  const prefersReduced = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  // Scroll progress bar
  const bar = document.createElement("div");
  bar.id = "scrollbar";
  document.body.appendChild(bar);

  // Mobile nav dropdown
  const navBtn = $("#navbtn");
  const links = $("#links");
  if (navBtn && links) {
    navBtn.addEventListener("click", () => links.classList.toggle("open"));
    document.addEventListener("click", (e) => {
      if (!links.classList.contains("open")) return;
      const within = e.target.closest("#links") || e.target.closest("#navbtn");
      if (!within) links.classList.remove("open");
    });
  }

  // Active link highlight
  const path = (location.pathname.split("/").pop() || "index.html").toLowerCase();
  $$(".links a").forEach((a) => {
    const h = (a.getAttribute("href") || "").toLowerCase();
    if (h === path) a.classList.add("active");
  });

  // =========================
  // Reveal system (premium)
  // =========================
  function markReveal() {
    const candidates = [
      ...$$(".head"),
      ...$$(".card"),
      ...$$(".media"),
      ...$$(".banner"),
      ...$$(".pagehero .wrap > *"),
      ...$$(".hero .wrap > *"),
    ];

    // Deduplicate
    const set = new Set(candidates.filter(Boolean));
    const els = Array.from(set);

    els.forEach((el) => {
      // avoid messing with nav/footer
      if (el.closest("header") || el.closest("footer")) return;
      el.classList.add("reveal");
    });

    // Stagger inside grids
    $$(".grid").forEach((g) => {
      const kids = [...g.children].filter((x) => x.classList && (x.classList.contains("card") || x.classList.contains("media")));
      kids.forEach((k, i) => k.style.setProperty("--d", `${Math.min(i * 70, 280)}ms`));
    });
  }

  function setupRevealObserver() {
    if (prefersReduced) {
      $$(".reveal").forEach((el) => el.classList.add("in"));
      return;
    }

    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (!e.isIntersecting) return;
          e.target.classList.add("in");
          io.unobserve(e.target);
        });
      },
      { threshold: 0.12, rootMargin: "0px 0px -10% 0px" }
    );

    $$(".reveal").forEach((el) => io.observe(el));
  }

  // =========================
  // Count-up for stats
  // =========================
  function parseNumber(text) {
    // keep digits only
    const raw = (text || "").toString().trim();
    const num = raw.replace(/[^\d]/g, "");
    return num ? Number(num) : 0;
  }

  function animateCount(el, to, ms = 900) {
    if (prefersReduced) {
      el.textContent = String(to);
      return;
    }
    const start = performance.now();
    const from = 0;
    el.classList.add("counting");

    const step = (t) => {
      const p = Math.min((t - start) / ms, 1);
      // easeOutCubic
      const eased = 1 - Math.pow(1 - p, 3);
      const val = Math.round(from + (to - from) * eased);
      el.textContent = String(val);
      if (p < 1) requestAnimationFrame(step);
      else el.classList.remove("counting");
    };
    requestAnimationFrame(step);
  }

  function setupStatCounts() {
    const nums = $$(".stat .num");
    if (!nums.length) return;

    // Store final values once
    nums.forEach((n) => {
      if (n.dataset.final) return;
      n.dataset.final = String(parseNumber(n.textContent));
      n.textContent = prefersReduced ? n.dataset.final : "0";
    });

    if (prefersReduced) return;

    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (!e.isIntersecting) return;
          const el = e.target;
          const to = Number(el.dataset.final || "0");
          animateCount(el, to, 900);
          io.unobserve(el);
        });
      },
      { threshold: 0.35 }
    );

    nums.forEach((n) => io.observe(n));
  }

  // =========================
  // Parallax (light + premium)
  // - hero video (p1)
  // - banners (p2)
  // - page hero background (p3)
  // =========================
  const heroVideo = $(".hero video");
  const banners = $$(".banner");
  const pageHero = $(".pagehero");

  let ticking = false;

  function onScroll() {
    const doc = document.documentElement;
    const scrollTop = doc.scrollTop || document.body.scrollTop || 0;
    const max = (doc.scrollHeight - doc.clientHeight) || 1;
    const prog = Math.max(0, Math.min(1, scrollTop / max));
    bar.style.width = `${prog * 100}%`;

    if (prefersReduced) return;

    if (!ticking) {
      ticking = true;
      requestAnimationFrame(() => {
        ticking = false;

        // Hero parallax
        if (heroVideo) {
          // small, classy drift
          const y = scrollTop * 0.08;
          heroVideo.style.setProperty("--p1", `${Math.max(-24, Math.min(24, y))}px`);
        }

        // Banner glow parallax
        banners.forEach((b) => {
          const r = b.getBoundingClientRect();
          const center = r.top + r.height / 2;
          const rel = (center - window.innerHeight / 2) / window.innerHeight;
          const y = rel * 22;
          b.style.setProperty("--p2", `${y}px`);
        });

        // Pagehero background drift
        if (pageHero) {
          const r = pageHero.getBoundingClientRect();
          const rel = r.top / (window.innerHeight || 1);
          const y = rel * 18;
          pageHero.style.setProperty("--p3", `${y}px`);
        }
      });
    }
  }

  // =========================
  // Lightbox (your existing)
  // =========================
  function initLightbox() {
    const triggers = $$("[data-open]");
    if (!triggers.length) return;

    const lb = document.createElement("div");
    lb.id = "lb";
    lb.innerHTML = `
      <div class="top">
        <div class="ttl" id="lbttl">Preview</div>
        <button class="x" id="lbx" aria-label="Close">✕</button>
      </div>
      <button class="nav prev" id="lbp" aria-label="Previous"><span>‹</span></button>
      <button class="nav next" id="lbn" aria-label="Next"><span>›</span></button>
      <div class="stage"><img id="lbimg" alt=""></div>
      <div class="thumbs" id="lbts" aria-label="Thumbnails"></div>
    `;
    document.body.appendChild(lb);

    const lbImg = $("#lbimg");
    const lbTtl = $("#lbttl");
    const lbTs = $("#lbts");
    const lbX = $("#lbx");
    const lbP = $("#lbp");
    const lbN = $("#lbn");

    let groups = {};
    let gname = "";
    let idx = 0;

    triggers.forEach((t) => {
      const g = t.getAttribute("data-group") || "default";
      groups[g] ??= [];
      groups[g].push({
        full: t.getAttribute("data-full") || t.getAttribute("href") || "",
        cap: t.getAttribute("data-cap") || "",
        thumb:
          t.getAttribute("data-thumb") ||
          t.querySelector("img")?.getAttribute("src") ||
          "",
      });
    });

    function render(items) {
      lbTs.innerHTML = "";
      items.forEach((it, i) => {
        const b = document.createElement("button");
        b.className = "t";
        b.type = "button";
        b.innerHTML = `<img src="${it.thumb || it.full}" alt="">`;
        b.addEventListener("click", () => set(i));
        lbTs.appendChild(b);
      });
    }

    function set(i) {
      const items = groups[gname] || [];
      if (!items.length) return;

      idx = (i + items.length) % items.length;
      const it = items[idx];

      lbImg.src = it.full;
      lbImg.alt = it.cap || "Image";
      lbTtl.textContent = it.cap || `Image ${idx + 1}`;

      const ts = $$(".t", lbTs);
      ts.forEach((x) => x.classList.remove("active"));
      if (ts[idx]) {
        ts[idx].classList.add("active");
        ts[idx].scrollIntoView({ behavior: "smooth", inline: "center", block: "nearest" });
      }
    }

    function open(group, i) {
      gname = group;
      const items = groups[gname] || [];
      if (!items.length) return;

      render(items);
      lb.classList.add("open");
      document.body.style.overflow = "hidden";
      set(i);
    }

    function close() {
      lb.classList.remove("open");
      document.body.style.overflow = "";
    }

    function prev() { set(idx - 1); }
    function next() { set(idx + 1); }

    triggers.forEach((t) =>
      t.addEventListener("click", (e) => {
        e.preventDefault();
        const g = t.getAttribute("data-group") || "default";
        const items = groups[g] || [];
        const full = t.getAttribute("data-full") || t.getAttribute("href") || "";
        const i = items.findIndex((x) => x.full === full);
        open(g, i >= 0 ? i : 0);
      })
    );

    lbX.addEventListener("click", close);
    lb.addEventListener("click", (e) => { if (e.target === lb) close(); });
    lbP.addEventListener("click", (e) => { e.preventDefault(); prev(); });
    lbN.addEventListener("click", (e) => { e.preventDefault(); next(); });

    document.addEventListener("keydown", (e) => {
      if (!lb.classList.contains("open")) return;
      if (e.key === "Escape") close();
      if (e.key === "ArrowLeft") prev();
      if (e.key === "ArrowRight") next();
    });

    let sx = null;
    lb.addEventListener("touchstart", (e) => {
      if (!lb.classList.contains("open")) return;
      sx = e.touches[0].clientX;
    }, { passive: true });

    lb.addEventListener("touchend", (e) => {
      if (!lb.classList.contains("open") || sx === null) return;
      const dx = e.changedTouches[0].clientX - sx;
      sx = null;
      if (Math.abs(dx) > 50) dx > 0 ? prev() : next();
    }, { passive: true });
  }

  // Boot
  markReveal();
  setupRevealObserver();
  setupStatCounts();
  initLightbox();

  // initial + bind
  onScroll();
  window.addEventListener("scroll", onScroll, { passive: true });
  window.addEventListener("resize", onScroll);
})();